async (params, browser) => {
  // Search AliExpress
  await browser.open(`https://www.aliexpress.com/w/wholesale-${params.query}.html`)

  // Wait for results
  await browser.waitForSelector('[class*=\'search-item\'], [class*=\'product-card\'], [class*=\'SearchResultList\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract product results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[class*="search-item-card"], [class*="product-card"], [class*="list--gallery"] > div, a[href*="/item/"]'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const titleEl = el.querySelector('h1, h3, [class*="title"], [class*="name"] a'); const priceEl = el.querySelector('[class*="price"], [class*="Price"]'); const ratingEl = el.querySelector('[class*="rating"], [class*="star"]'); const ordersEl = el.querySelector('[class*="sold"], [class*="orders"]'); const imgEl = el.querySelector('img'); const linkEl = el.tagName === 'A' ? el : el.querySelector('a[href*="/item/"]'); const storeEl = el.querySelector('[class*="store"], [class*="shop"]'); results.push({ title: titleEl ? titleEl.textContent.trim().substring(0, 200) : '', price: priceEl ? priceEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', orders: ordersEl ? ordersEl.textContent.trim() : '', store: storeEl ? storeEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
